      chords: [
        { name: "Major triad", formula: "root + major third + perfect fifth", sound: "Stable triad; the major third defines the quality.", listenFor: "The fifth matches minor, so focus on the third that defines the chord quality." },
        { name: "Minor triad", formula: "root + minor third + perfect fifth", sound: "Stable triad with a narrower third.", listenFor: "Compare the third: it is one semitone lower than major." },
        { name: "Diminished triad", formula: "root + minor third + diminished fifth", sound: "Compressed and tense because the fifth is lowered.", listenFor: "After the third, check whether the upper support is lowered and unstable." },
        { name: "Augmented triad", formula: "root + major third + augmented fifth", sound: "Stretched and unstable because the fifth is raised.", listenFor: "Hear whether the top note feels lifted above a stable fifth." }
      ],
      seventhChords: {
        intro: "A seventh chord = a triad plus a seventh above the root.",
        tension: "The added seventh creates mild or stronger tension because the upper note often wants to move toward a more stable place.",
        types: [
          { name: "Dominant 7th", formula: "major triad + minor seventh", sound: "Major base with clear added tension on top.", listenFor: "Identify the major triad first, then the added minor seventh." },
          { name: "Major 7th", formula: "major triad + major seventh", sound: "Major base with an upper note very close to the octave.", listenFor: "Hear the high seventh almost touching the upper root." },
          { name: "Minor 7th", formula: "minor triad + minor seventh", sound: "Minor base with a softer added tension.", listenFor: "Find the minor third first, then the extra upper seventh." },
          { name: "Half-diminished 7th", formula: "diminished triad + minor seventh", sound: "Compressed diminished base with a minor seventh on top.", listenFor: "Hear the lowered fifth, then compare the seventh with the octave." },
          { name: "Diminished 7th", formula: "diminished triad + diminished seventh", sound: "Highly tense and symmetrically compressed.", listenFor: "Compare with half-diminished: the top note is lower." }
        ]
      },
      scales: [
        { name: "Major", structure: "whole–whole–half–whole–whole–whole–half", character: "Stable scale with clear half steps between degrees 3–4 and 7–8.", unique: "The 7th degree strongly pulls to the upper root." },
        { name: "Natural minor", structure: "whole–half–whole–whole–half–whole–whole", character: "Minor mode without a raised 7th degree.", unique: "The lowered 3rd degree appears very early." },
        { name: "Harmonic minor", structure: "minor with raised degree 7", character: "Minor with strong pull to the upper root.", unique: "Large step between degree 6 and raised degree 7." },
        { name: "Melodic minor", structure: "minor with raised degrees 6 and 7 ascending", character: "Minor beginning with a smoother upper half.", unique: "The 3rd is minor, but degrees 6 and 7 sound higher." },
        { name: "Dorian", structure: "minor with raised degree 6", character: "Minor, but more open than natural minor.", unique: "Raised 6th separates it from natural minor." },
        { name: "Phrygian", structure: "minor with lowered degree 2", character: "Tense from the very first step.", unique: "The first upward motion is a minor 2nd." },
        { name: "Lydian", structure: "major with raised degree 4", character: "Major base with an unstable raised fourth.", unique: "#4 is the characteristic lifted signal." },
        { name: "Mixolydian", structure: "major with lowered degree 7", character: "Major without strong leading-tone pull to the octave.", unique: "Lowered 7th makes the ending less tense." }
      ],
      tension: [
        { title: "Stable sounds", text: "Octaves, fifths, and root notes often feel like anchors or resting places." },
        { title: "Unstable sounds", text: "Tritones, sevenths, and altered fifths create tension and seem to ask for a next step." },
        { title: "Simple example", text: "A seventh almost reaches the octave, so it often wants to resolve to a more stable sound." }
      ],
      melody: [
        { title: "Melody has direction", text: "A melody is remembered not only by notes, but by motion: up, down, or staying in place." },
        { title: "Stable ending", text: "A phrase often feels complete when it arrives on a stable tone." },
        { title: "Tension", text: "Unstable tones create expectation and usually want to move somewhere next." }
      ],
      songHarmony: [
        { title: "A few chords", text: "Many simple songs can be accompanied by a few basic chords, although music is not limited to only those chords." },
        { title: "Foundation", text: "Major and minor triads are the foundation for understanding chords in songs." },
        { title: "Why quality matters", text: "Recognizing chord quality helps you understand and recreate music by ear." }
      ]
